"""Tests for the Hebrew morphology-light spike plugin.

The Hebrew plugin is a starter (no morphological NLP library available).
It provides:
  - Sentence splitting on standard terminal punctuation and newlines
  - Whitespace tokenisation over the Hebrew Unicode block
  - Nikud (vowel-point) + cantillation stripping for canonical forms
  - RTL direction metadata and hebrew script-family for frontend rendering

Tests deliberately avoid asserting linguistic correctness of Hebrew grammar;
they verify the *plugin contract* and *honest capability declarations*.
"""
from __future__ import annotations

import pytest

from backend.plugins.hebrew import (
    HebrewPlugin,
    _strip_nikud,
    create_plugin,
)
from backend.schemas.language import LanguageCapabilities
from backend.schemas.parse import CandidateObject, CandidateSentenceResult


# ── Fixtures ───────────────────────────────────────────────────────────────────

