# ── Nikud (vowel-point) stripping ─────────────────────────────────────────────

class TestNikudStripping:
    def test_strips_dagesh(self) -> None:
        # ּ (U+05BC dagesh) should be removed.
        assert _strip_nikud("שַׁבָּת") == "שבת"

    def test_strips_holam(self) -> None:
        # ָ (qamats) and ֹ (holam) stripped.
        assert _strip_nikud("תּוֹרָה") == "תורה"

    def test_strips_shva(self) -> None:
        # ְ (U+05B0 shva) stripped.
        word_with_shva = "בְּרֵאשִׁית"
        result = _strip_nikud(word_with_shva)
        assert result == "בראשית"

    def test_plain_text_unchanged(self) -> None:
        assert _strip_nikud("ספר") == "ספר"

    def test_latin_text_unchanged(self) -> None:
        # Non-Hebrew text should pass through unmodified.
        assert _strip_nikud("hello") == "hello"

    def test_empty_string_unchanged(self) -> None:
        assert _strip_nikud("") == ""

    def test_strips_cantillation_marks(self) -> None:
        # Cantillation (te'amim) used in Biblical Hebrew — should be removed.
        # U+0591 (etnahta) is in the cantillation range.
        with_cantillation = "בְּרֵאשִׁ֖ית"
        result = _strip_nikud(with_cantillation)
        # No combining characters should remain
        assert all(ord(c) < 0x0591 or ord(c) > 0x05C7 for c in result)


# ── Sentence splitting ─────────────────────────────────────────────────────────

class TestSentenceSplitting:
    def test_splits_on_full_stop(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("שלום. שוב.")
        assert len(sentences) == 2

    def test_splits_on_question_mark(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("מה שלומך? טוב מאוד.")
        assert len(sentences) == 2

    def test_splits_on_exclamation(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("שלום! ברוך הבא!")
        assert len(sentences) == 2

    def test_splits_on_newline(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("שלום\nעולם")
        assert len(sentences) == 2

    def test_single_sentence_no_punctuation(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("שלום עולם")
        assert len(sentences) == 1

    def test_empty_string_returns_empty_list(self, plugin: HebrewPlugin) -> None:
        assert plugin.split_sentences("") == []

    def test_whitespace_only_returns_empty_list(self, plugin: HebrewPlugin) -> None:
        assert plugin.split_sentences("   ") == []

    def test_sentences_are_stripped(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("  שלום.  ")
        assert all(s == s.strip() for s in sentences)

    def test_sentences_are_non_empty(self, plugin: HebrewPlugin) -> None:
        sentences = plugin.split_sentences("שלום. מה שלומך?")
        assert all(len(s) > 0 for s in sentences)


# ── Word tokenisation and candidate extraction ────────────────────────────────

class TestCandidateExtraction:
    def test_hebrew_words_extracted(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("שלום עולם")
        assert len(result.candidates) == 2

    def test_each_candidate_is_vocabulary_type(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר גדול")
        for c in result.candidates:
            assert c.type == "vocabulary"

    def test_sentence_text_preserved(self, plugin: HebrewPlugin) -> None:
        sentence = "הילד קרא ספר."
        result = plugin.analyze_sentence(sentence)
        assert result.text == sentence

    def test_candidate_has_non_empty_label(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("שלום עולם")
        for c in result.candidates:
            assert c.label and len(c.label) > 0

    def test_candidate_has_canonical_form(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("שלום")
        for c in result.candidates:
            assert c.canonical_form

    def test_latin_text_produces_no_candidates(self, plugin: HebrewPlugin) -> None:
        # The word regex matches only Hebrew Unicode block characters.
        result = plugin.analyze_sentence("Hello world")
        assert result.candidates == []

    def test_punctuation_only_produces_no_candidates(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence(".,!?")
        assert result.candidates == []

    def test_empty_sentence_produces_no_candidates(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("")
        assert result.candidates == []

    def test_mixed_hebrew_latin_only_hebrew_extracted(self, plugin: HebrewPlugin) -> None:
        # Latin text should not appear as candidates.
        result = plugin.analyze_sentence("שלום hello")
        canonical_forms = {c.canonical_form for c in result.candidates}
        assert "hello" not in canonical_forms
        assert "שלום" in canonical_forms

    def test_numerals_not_extracted_as_words(self, plugin: HebrewPlugin) -> None:
        # ASCII digits are not in the Hebrew Unicode block.
        result = plugin.analyze_sentence("123 ספרים")
        canonical_forms = {c.canonical_form for c in result.candidates}
        assert "123" not in canonical_forms


# ── Nikud canonicalisation in candidates ──────────────────────────────────────

class TestNikudCanonicalization:
    def test_nikud_stripped_in_canonical_form(self, plugin: HebrewPlugin) -> None:
        # שַׁבָּת with vowel points → canonical ספ without vowel points.
        result = plugin.analyze_sentence("שַׁבָּת")
        assert result.candidates
        # Canonical form must not contain nikud.
        for c in result.candidates:
            stripped = _strip_nikud(c.canonical_form)
            assert stripped == c.canonical_form

    def test_surface_form_preserves_nikud(self, plugin: HebrewPlugin) -> None:
        # Surface form is the original token from the text, nikud intact.
        word_with_nikud = "שַׁבָּת"
        result = plugin.analyze_sentence(word_with_nikud)
        if result.candidates:
            c = result.candidates[0]
            # Canonical form should be shorter (nikud stripped).
            assert len(c.canonical_form) <= len(c.surface_form or "")

    def test_nikud_and_plain_same_canonical_form(self, plugin: HebrewPlugin) -> None:
        # "שַׁבָּת" and "שבת" must produce the same canonical form.
        result_with_nikud = plugin.analyze_sentence("שַׁבָּת")
        result_plain = plugin.analyze_sentence("שבת")
        if result_with_nikud.candidates and result_plain.candidates:
            assert (
                result_with_nikud.candidates[0].canonical_form
                == result_plain.candidates[0].canonical_form
            )


# ── Lesson data ───────────────────────────────────────────────────────────────

class TestLessonData:
    def test_lesson_data_has_lemma(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר")
        for c in result.candidates:
            assert "lemma" in c.lesson_data

    def test_lesson_data_lemma_matches_canonical(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר")
        for c in result.candidates:
            assert c.lesson_data["lemma"] == c.canonical_form

    def test_lesson_data_has_confidence_note(self, plugin: HebrewPlugin) -> None:
        # Honest disclosure must be present in every card.
        result = plugin.analyze_sentence("ספר גדול")
        for c in result.candidates:
            assert "confidence_note" in c.lesson_data
            note = c.lesson_data["confidence_note"]
            assert isinstance(note, str) and len(note) > 0

    def test_confidence_note_mentions_prefix_limitation(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר")
        for c in result.candidates:
            note = c.lesson_data.get("confidence_note", "")
            # The note must acknowledge that inseparable prefixes aren't split.
            assert "prefix" in note.lower() or "prefix" in note

    def test_heuristic_binyan_for_common_verb(self, plugin: HebrewPlugin) -> None:
        from backend.morphology import he_adapter as _he_adapter
        if _he_adapter.is_available():
            pytest.skip("HebSpaCy active: binyan data comes from the model")
        result = plugin.analyze_sentence("כתב ספר")
        by_form = {c.canonical_form: c for c in result.candidates}
        assert by_form["כתב"].lesson_data["root"] == "כ.ת.ב"
        assert by_form["כתב"].lesson_data["binyan"] == "Pa'al"
        assert by_form["כתב"].lesson_data["tense"] == "Past"
        assert by_form["כתב"].lesson_data["morphology_source"] == "heuristic"

    def test_prefix_false_positive_blocklist_keeps_shalom_intact(self, plugin: HebrewPlugin) -> None:
        from backend.morphology import he_adapter as _he_adapter
        if _he_adapter.is_available():
            pytest.skip("HebSpaCy active: prefix handling comes from the model")
        result = plugin.analyze_sentence("שלום")
        c = result.candidates[0]
        assert c.canonical_form == "שלום"
        assert c.lesson_data["lemma"] == "שלום"
        assert c.lesson_data.get("prefix", "") == ""


# ── Deduplication ─────────────────────────────────────────────────────────────

class TestDeduplication:
    def test_repeated_word_appears_once(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר ספר ספר")
        canonical_forms = [c.canonical_form for c in result.candidates]
        assert len(canonical_forms) == len(set(canonical_forms))
        assert canonical_forms.count("ספר") == 1

    def test_nikud_variants_of_same_word_deduplicated(self, plugin: HebrewPlugin) -> None:
        # שַׁבָּת and שבת are the same word; only one candidate expected.
        result = plugin.analyze_sentence("שַׁבָּת שבת")
        canonical_forms = [c.canonical_form for c in result.candidates]
        assert len(set(canonical_forms)) == len(canonical_forms)  # no dupes

    def test_different_words_not_deduplicated(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_sentence("ספר עולם")
        assert len(result.candidates) == 2


# ── Edge cases ────────────────────────────────────────────────────────────────

class TestEdgeCases:
    def test_single_letter_word_extracted(self, plugin: HebrewPlugin) -> None:
        # Prepositions like ב / ל / כ as standalone characters are valid tokens.
        result = plugin.analyze_sentence("ב")
        # Should produce a candidate (single letter is still a Hebrew token).
        assert len(result.candidates) >= 0  # don't crash

    def test_analyze_text_consistent_with_analyze_sentence(
        self, plugin: HebrewPlugin
    ) -> None:
        text = "שלום. מה שלומך?"
        multi_result = plugin.analyze_text(text)
        sentences = plugin.split_sentences(text)
        assert len(multi_result) == len(sentences)

    def test_idempotent_analysis(self, plugin: HebrewPlugin) -> None:
        sentence = "הילד קרא ספר."
        r1 = plugin.analyze_sentence(sentence)
        r2 = plugin.analyze_sentence(sentence)
        forms1 = [c.canonical_form for c in r1.candidates]
        forms2 = [c.canonical_form for c in r2.candidates]
        assert forms1 == forms2

    def test_all_returned_types_are_vocabulary_or_nuance(self, plugin: HebrewPlugin) -> None:
        result = plugin.analyze_text("הילד הקטן קרא ספר מעניין.")
        allowed = {"vocabulary", "nuance"}
        for sent in result:
            for c in sent.candidates:
                assert c.type in allowed


# ── Lesson store ──────────────────────────────────────────────────────────────

class TestLessonStore:
    def test_missing_id_returns_none(self, plugin: HebrewPlugin) -> None:
        assert plugin.get_lesson("nonexistent-id") is None

    def test_stored_object_is_retrievable(self, plugin: HebrewPlugin) -> None:
        obj = CandidateObject(
            canonical_form="ספר",
            surface_form="ספר",
            type="vocabulary",
            label="ספר",
            lesson_data={"lemma": "ספר"},
        )
        plugin.lesson_store["test-id-001"] = obj
        assert plugin.get_lesson("test-id-001") is obj

    def test_lesson_stores_are_independent_across_instances(self) -> None:
        p1 = create_plugin()
        p2 = create_plugin()
        obj = CandidateObject(
            canonical_form="ספר",
            surface_form="ספר",
            type="vocabulary",
            label="ספר",
            lesson_data={},
        )
        p1.lesson_store["x"] = obj
        assert p2.get_lesson("x") is None


# ── Multilingual architecture integration ─────────────────────────────────────

class TestMultilingualArchitecture:
    def test_hebrew_registered_in_plugin_loader(self) -> None:
        from backend.parsing.plugin_loader import load_plugins
        registry = load_plugins()
        assert "he" in registry.all()

    def test_hebrew_capabilities_in_registry(self) -> None:
        from backend.parsing.plugin_loader import load_plugins
        registry = load_plugins()
        caps = registry.supported_languages()
        assert "he" in caps
        assert caps["he"].direction == "rtl"
        assert caps["he"].script_family == "hebrew"

    def test_hebrew_and_arabic_ids_differ(self) -> None:
        from backend.parsing.canonical import canonical_object_id
        he_id = canonical_object_id("he", "vocabulary", "ספר")
        ar_id = canonical_object_id("ar", "vocabulary", "كتاب")
        assert he_id != ar_id

    def test_same_he_word_same_canonical_id(self) -> None:
        from backend.parsing.canonical import canonical_object_id
        id1 = canonical_object_id("he", "vocabulary", "ספר")
        id2 = canonical_object_id("he", "vocabulary", "ספר")
        assert id1 == id2

    def test_canonical_id_is_uuid_format(self) -> None:
        import uuid
        from backend.parsing.canonical import canonical_object_id
        raw = canonical_object_id("he", "vocabulary", "ספר")
        uuid.UUID(raw)  # raises ValueError if not a valid UUID

    def test_hebrew_direction_rtl_not_shared_with_zh(self) -> None:
        from backend.parsing.plugin_loader import load_plugins
        registry = load_plugins()
        caps = registry.supported_languages()
        assert caps["he"].direction == "rtl"
        assert caps["zh"].direction == "ltr"
